1	/**
2	 * OS credential storage using Electron's built-in safeStorage API.
3	 *
4	 * safeStorage uses the OS credential store under the hood:
5	 *  - Windows: DPAPI (Data Protection API)
6	 *  - macOS: Keychain
7	 *  - Linux: Secret Service / fallback encryption
8	 *
9	 * Encrypted blobs are stored in a JSON file in userData.
10	 * No native module compilation needed — safeStorage is part of Electron.
11	 */
12	
13	import { safeStorage, app } from "electron";
14	import { join } from "path";
15	import { readFileSync, writeFileSync, mkdirSync } from "fs";
16	import { log } from "./logger";
17	
18	const STORE_PATH = join(app.getPath("userData"), "credentials.enc.json");
19	
20	function loadStore(): Record<string, string> {
21	  try {
22	    const raw = readFileSync(STORE_PATH, "utf-8");
23	    return JSON.parse(raw);
24	  } catch {
25	    return {};
26	  }
27	}
28	
29	function saveStore(store: Record<string, string>): void {
30	  mkdirSync(app.getPath("userData"), { recursive: true });
31	  writeFileSync(STORE_PATH, JSON.stringify(store), "utf-8");
32	}
33	
34	export function storeToken(account: string, token: string): void {
35	  if (!safeStorage.isEncryptionAvailable()) {
36	    log.warn("safeStorage encryption not available — skipping credential store");
37	    return;
38	  }
39	  const store = loadStore();
40	  store[account] = safeStorage.encryptString(token).toString("base64");
41	  saveStore(store);
42	}
43	
44	export function loadToken(account: string): string | null {
45	  if (!safeStorage.isEncryptionAvailable()) return null;
46	  const store = loadStore();
47	  const enc = store[account];
48	  if (!enc) return null;
49	  try {
50	    return safeStorage.decryptString(Buffer.from(enc, "base64"));
51	  } catch {
52	    return null;
53	  }
54	}
55	
56	export function deleteToken(account: string): void {
57	  const store = loadStore();
58	  delete store[account];
59	  saveStore(store);
60	}
61	
62	export function storeSession(accessToken: string, refreshToken: string): void {
63	  storeToken("access_token", accessToken);
64	  storeToken("refresh_token", refreshToken);
65	}
66	
67	export function loadSession(): { accessToken: string; refreshToken: string } | null {
68	  const accessToken = loadToken("access_token");
69	  const refreshToken = loadToken("refresh_token");
70	  if (!accessToken || !refreshToken) return null;
