1	/**
2	 * helper-api — all communication between the POP DAM Helper (Electron app)
3	 * and the cloud. Also used by the web DAM to generate popdam:// URL tokens.
4	 *
5	 * Routes (method + path suffix after /helper-api):
6	 *
7	 *   POST  /register-device          Helper on first run / version change
8	 *   GET   /config                   Helper on startup — root mappings + DAM URL
9	 *   POST  /tokens                   Web DAM — generate a short-lived popdam:// token
10	 *   POST  /checkouts/start          Helper — validate token, create checkout lock
11	 *   POST  /checkouts/prepare-checkin  Helper — validate snapshot, get upload instructions
12	 *   POST  /checkouts/complete-checkin Helper — record final hash, unlock asset
13	 *   POST  /checkouts/discard        Helper or web — abandon a checkout
14	 *   POST  /checkouts/heartbeat      Helper — keep checkout alive, report status
15	 *   GET   /checkouts/open           Helper on startup — list user's active checkouts
16	 *   POST  /logs                     Helper — store audit / error events
17	 */
18	
19	import { corsServe, err, json } from "../_shared/http.ts";
20	import { serviceClient } from "../_shared/service-client.ts";
21	import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
22	
23	// ── Auth helpers ──────────────────────────────────────────────────────────────
24	
25	async function getUserId(req: Request): Promise<string | null> {
26	  const auth = req.headers.get("Authorization");
27	  if (!auth?.startsWith("Bearer ")) return null;
28	  const token = auth.slice(7);
29	  const client = createClient(
30	    Deno.env.get("SUPABASE_URL")!,
31	    Deno.env.get("SUPABASE_ANON_KEY")!,
32	  );
33	  const { data: { user }, error } = await client.auth.getUser(token);
34	  if (error || !user) return null;
35	  return user.id;
36	}
