116	    dam_url: (cfg["HELPER_DAM_URL"] as string) ?? null,
117	    synology_url: (cfg["HELPER_SYNOLOGY_URL"] as string) ?? null,
118	    synology_port: (cfg["HELPER_SYNOLOGY_PORT"] as string) ?? "5001",
