184	async function handleStartCheckout(req: Request): Promise<Response> {
185	  const userId = await getUserId(req);
186	  if (!userId) return err("Unauthorized", 401);
187	
188	  const body = await req.json();
189	  const { token, asset_id, device_id, helper_version, computer_id } = body;
190	  if (!token) return err("token required");
191	
192	  const db = serviceClient();
193	
194	  // Validate and consume token
195	  const { data: tok, error: tokErr } = await db
196	    .from("helper_tokens")
197	    .select("*")
198	    .eq("id", token)
199	    .eq("user_id", userId)
200	    .eq("action", "checkout")
201	    .single();
202	
203	  if (tokErr || !tok) return err("Invalid or expired token", 401);
204	  if (tok.consumed_at) return err("Token already used", 401);
205	  if (new Date(tok.expires_at) < new Date()) return err("Token expired", 401);
206	  if (tok.asset_id && asset_id && tok.asset_id !== asset_id) {
207	    return err("Token asset mismatch", 401);
208	  }
209	
210	  const resolvedAssetId = tok.asset_id ?? asset_id;
211	  if (!resolvedAssetId) return err("asset_id required");
212	
213	  // Load asset
214	  const { data: asset } = await db
215	    .from("assets")
216	    .select("id, filename, relative_path, quick_hash, file_size, is_deleted")
217	    .eq("id", resolvedAssetId)
218	    .single();
219	  if (!asset || asset.is_deleted) return err("Asset not found");
220	
221	  // Check for conflicting active checkout
222	  const { data: existing } = await db
223	    .from("asset_checkouts")
224	    .select("id, user_id")
225	    .eq("asset_id", resolvedAssetId)
226	    .in("status", ["active", "checkin_queued", "uploading", "verifying"])
227	    .maybeSingle();
228	
229	  if (existing && existing.user_id !== userId) {
230	    return err("Asset is checked out by another user", 409);
231	  }
232	  if (existing && existing.user_id === userId) {
233	    // Already checked out by this user — mark token consumed and return existing checkout
234	    await db
235	      .from("helper_tokens")
236	      .update({ consumed_at: new Date().toISOString() })
237	      .eq("id", token);
238	    return json({ ok: true, checkout_id: existing.id, already_open: true, asset });
239	  }
240	
241	  // Create checkout record
242	  const { data: checkout, error: coErr } = await db
243	    .from("asset_checkouts")
244	    .insert({
245	      asset_id: resolvedAssetId,
246	      user_id: userId,
247	      device_id: device_id ?? null,
248	      status: "active",
249	      source_hash: asset.quick_hash ?? "",
250	      source_size: asset.file_size ?? 0,
251	    })
252	    .select("id")
253	    .single();
254	
255	  if (coErr) {
256	    // Unique constraint violation — race with another user
257	    if (coErr.code === "23505") return err("Asset was just checked out by another user", 409);
258	    return err(`Failed to create checkout: ${coErr.message}`, 500);
259	  }
260	
261	  // Consume token and link it to the checkout
262	  await db
263	    .from("helper_tokens")
264	    .update({ consumed_at: new Date().toISOString(), checkout_id: checkout.id })
265	    .eq("id", token);
266	
267	  // Load root mapping from admin_config so helper knows where to look
268	  const { data: cfgRow } = await db
269	    .from("admin_config")
270	    .select("value")
271	    .eq("key", "HELPER_ROOT_MAPPINGS")
272	    .maybeSingle();
273	  const rootMappings = cfgRow?.value ? JSON.parse(cfgRow.value) : [];
274	
275	  return json({
276	    ok: true,
277	    checkout_id: checkout.id,
278	    asset: {
279	      asset_id: asset.id,
280	      filename: asset.filename,
281	      relative_path: asset.relative_path,
282	      expected_hash: asset.quick_hash,
283	      expected_size: asset.file_size,
284	    },
285	    root_mappings: rootMappings,
286	    open_after_checkout: true,
287	  });
288	}
