515	  if (method === "POST" && path === "/checkouts/complete-checkin") return handleCompleteCheckin(req);
516	  if (method === "POST" && path === "/checkouts/discard") return handleDiscard(req);
517	  if (method === "POST" && path === "/checkouts/heartbeat") return handleHeartbeat(req);
518	  if (method === "GET" && path === "/checkouts/open") return handleGetOpenCheckouts(req);
