1	/**
2	 * Validates that a chosen local folder is the correct root for a given root_id.
3	 *
4	 * Rules:
5	 *  1. Path must not be in the forbidden list (C:\, /Users, etc.)
6	 *  2. Path must contain a .pop-root.json marker file
7	 *  3. Marker root_id must match expected root_id
8	 *  4. If marker is found in a subfolder, suggest the correct root
9	 */
10	
11	import { join, dirname, sep } from "path";
12	import { existsSync, readFileSync, readdirSync, statSync, writeFileSync } from "fs";
13	import {
14	  FORBIDDEN_ROOT_PREFIXES_WIN,
15	  FORBIDDEN_ROOT_PREFIXES_MAC,
16	  ROOT_MARKER_FILENAME,
17	} from "@shared/constants";
18	
19	export interface MarkerFile {
20	  type: string;
21	  root_id: string;
22	  company?: string;
23	  canonical_server_path?: string;
24	  schema_version?: number;
25	}
26	
27	export type ValidationResult =
28	  | { ok: true; resolvedPath: string }
29	  | { ok: false; reason: "forbidden"; message: string }
30	  | { ok: false; reason: "no_marker"; message: string }
31	  | { ok: false; reason: "wrong_root_id"; expected: string; actual: string; message: string }
32	  | { ok: false; reason: "too_deep"; suggestedPath: string; message: string }
33	  | { ok: false; reason: "too_shallow"; suggestedPath: string; message: string };
34	
35	function isForbidden(p: string): boolean {
36	  const prefixes =
37	    process.platform === "win32"
38	      ? FORBIDDEN_ROOT_PREFIXES_WIN
39	      : FORBIDDEN_ROOT_PREFIXES_MAC;
40	  // Normalize to lowercase on Windows
41	  const norm = process.platform === "win32" ? p.toLowerCase() : p;
42	  return prefixes.some((prefix) => {
43	    const normPrefix = process.platform === "win32" ? prefix.toLowerCase() : prefix;
44	    return norm === normPrefix || norm === normPrefix + sep;
45	  });
46	}
47	
48	function readMarker(dir: string): MarkerFile | null {
49	  const markerPath = join(dir, ROOT_MARKER_FILENAME);
50	  if (!existsSync(markerPath)) return null;
51	  try {
52	    return JSON.parse(readFileSync(markerPath, "utf-8"));
53	  } catch {
54	    return null;
55	  }
56	}
57	
58	/**
59	 * Search up to 4 levels up and 2 levels down for a marker file.
60	 * Used to auto-correct if the user selected a subfolder or parent folder.
61	 */
62	function findMarkerNearby(startPath: string): { path: string; marker: MarkerFile } | null {
63	  // Check the path itself first
64	  const direct = readMarker(startPath);
65	  if (direct) return { path: startPath, marker: direct };
66	
67	  // Check up to 4 levels up
68	  let current = startPath;
69	  for (let i = 0; i < 4; i++) {
70	    const parent = dirname(current);
71	    if (parent === current) break; // reached fs root
72	    const m = readMarker(parent);
73	    if (m) return { path: parent, marker: m };
74	    current = parent;
75	  }
76	
77	  // Check 2 levels down (immediate children and their children)
78	  function searchDown(dir: string, depth: number): { path: string; marker: MarkerFile } | null {
79	    if (depth === 0) return null;
80	    try {
81	      const entries = readdirSync(dir);
82	      for (const entry of entries) {
83	        const child = join(dir, entry);
84	        try {
85	          if (statSync(child).isDirectory()) {
86	            const m = readMarker(child);
87	            if (m) return { path: child, marker: m };
88	            const deeper = searchDown(child, depth - 1);
89	            if (deeper) return deeper;
90	          }
91	        } catch { /* skip */ }
92	      }
93	    } catch { /* skip */ }
94	    return null;
95	  }
96	  const down = searchDown(startPath, 2);
97	  if (down) return down;
98	
99	  return null;
100	}
101	
102	export function validateRoot(chosenPath: string, expectedRootId: string): ValidationResult {
103	  if (isForbidden(chosenPath)) {
104	    return {
105	      ok: false,
106	      reason: "forbidden",
107	      message: `"${chosenPath}" is too broad. Please choose a dedicated folder like C:\\POP-Files or ~/POP-Files.`,
108	    };
109	  }
110	
111	  const directMarker = readMarker(chosenPath);
112	
113	  if (directMarker) {
114	    if (directMarker.root_id !== expectedRootId) {
115	      return {
116	        ok: false,
117	        reason: "wrong_root_id",
118	        expected: expectedRootId,
119	        actual: directMarker.root_id,
120	        message: `This folder is marked as "${directMarker.root_id}", but "${expectedRootId}" is expected.`,
121	      };
122	    }
123	    return { ok: true, resolvedPath: chosenPath };
124	  }
125	
126	  // No direct marker — search nearby
127	  const nearby = findMarkerNearby(chosenPath);
128	
129	  if (!nearby) {
130	    return {
131	      ok: false,
132	      reason: "no_marker",
133	      message: `No POP root marker found in or near "${chosenPath}". Contact your IT admin to set up the root.`,
134	    };
135	  }
136	
137	  if (nearby.path !== chosenPath) {
138	    // Marker found in a parent or child — the user picked the wrong level
