/**
 * Validates that a chosen local folder is the correct root for a given root_id.
 *
 * Rules:
 *  1. Path must not be in the forbidden list (C:\, /Users, etc.)
 *  2. Path must contain a .pop-root.json marker file
 *  3. Marker root_id must match expected root_id
 *  4. If marker is found in a subfolder, suggest the correct root
 */

import { join, dirname, sep } from "path";
import { existsSync, readFileSync, readdirSync, statSync, writeFileSync } from "fs";
import {
  FORBIDDEN_ROOT_PREFIXES_WIN,
  FORBIDDEN_ROOT_PREFIXES_MAC,
  ROOT_MARKER_FILENAME,
} from "@shared/constants";

export interface MarkerFile {
  type: string;
  root_id: string;
  company?: string;
  canonical_server_path?: string;
  schema_version?: number;
}

export type ValidationResult =
  | { ok: true; resolvedPath: string }
  | { ok: false; reason: "forbidden"; message: string }
  | { ok: false; reason: "no_marker"; message: string }
  | { ok: false; reason: "wrong_root_id"; expected: string; actual: string; message: string }
  | { ok: false; reason: "too_deep"; suggestedPath: string; message: string }
  | { ok: false; reason: "too_shallow"; suggestedPath: string; message: string };

function isForbidden(p: string): boolean {
  const prefixes =
    process.platform === "win32"
      ? FORBIDDEN_ROOT_PREFIXES_WIN
      : FORBIDDEN_ROOT_PREFIXES_MAC;
  // Normalize to lowercase on Windows
  const norm = process.platform === "win32" ? p.toLowerCase() : p;
  return prefixes.some((prefix) => {
    const normPrefix = process.platform === "win32" ? prefix.toLowerCase() : prefix;
    return norm === normPrefix || norm === normPrefix + sep;
  });
}

function readMarker(dir: string): MarkerFile | null {
  const markerPath = join(dir, ROOT_MARKER_FILENAME);
  if (!existsSync(markerPath)) return null;
  try {
    return JSON.parse(readFileSync(markerPath, "utf-8"));
  } catch {
    return null;
  }
}

/**
 * Search up to 4 levels up and 2 levels down for a marker file.
 * Used to auto-correct if the user selected a subfolder or parent folder.
 */
function findMarkerNearby(startPath: string): { path: string; marker: MarkerFile } | null {
  // Check the path itself first
  const direct = readMarker(startPath);
  if (direct) return { path: startPath, marker: direct };

  // Check up to 4 levels up
  let current = startPath;
  for (let i = 0; i < 4; i++) {
    const parent = dirname(current);
    if (parent === current) break; // reached fs root
    const m = readMarker(parent);
    if (m) return { path: parent, marker: m };
    current = parent;
  }

  // Check 2 levels down (immediate children and their children)
  function searchDown(dir: string, depth: number): { path: string; marker: MarkerFile } | null {
    if (depth === 0) return null;
    try {
      const entries = readdirSync(dir);
      for (const entry of entries) {
        const child = join(dir, entry);
        try {
          if (statSync(child).isDirectory()) {
            const m = readMarker(child);
            if (m) return { path: child, marker: m };
            const deeper = searchDown(child, depth - 1);
            if (deeper) return deeper;
          }
        } catch { /* skip */ }
      }
    } catch { /* skip */ }
    return null;
  }
  const down = searchDown(startPath, 2);
  if (down) return down;

  return null;
}

export function validateRoot(chosenPath: string, expectedRootId: string): ValidationResult {
  if (isForbidden(chosenPath)) {
    return {
      ok: false,
      reason: "forbidden",
      message: `"${chosenPath}" is too broad. Please choose a dedicated folder like C:\\POP-Files or ~/POP-Files.`,
    };
  }

  const directMarker = readMarker(chosenPath);

  if (directMarker) {
    if (directMarker.root_id !== expectedRootId) {
      return {
        ok: false,
        reason: "wrong_root_id",
        expected: expectedRootId,
        actual: directMarker.root_id,
        message: `This folder is marked as "${directMarker.root_id}", but "${expectedRootId}" is expected.`,
      };
    }
    return { ok: true, resolvedPath: chosenPath };
  }

  // No direct marker — search nearby
  const nearby = findMarkerNearby(chosenPath);

  if (!nearby) {
    return {
      ok: false,
      reason: "no_marker",
      message: `No POP root marker found in or near "${chosenPath}". Contact your IT admin to set up the root.`,
    };
  }

  if (nearby.path !== chosenPath) {
    // Marker found in a parent or child — the user picked the wrong level
    const depth = chosenPath.split(sep).length - nearby.path.split(sep).length;
    if (depth > 0) {
      // User picked a subfolder
      return {
        ok: false,
        reason: "too_deep",
        suggestedPath: nearby.path,
        message: `You selected a subfolder inside the root. The correct root appears to be:\n${nearby.path}`,
      };
    } else {
      // User picked a parent folder
      return {
        ok: false,
        reason: "too_shallow",
        suggestedPath: nearby.path,
        message: `You selected a parent folder. The correct root appears to be:\n${nearby.path}`,
      };
    }
  }

  return {
    ok: false,
    reason: "no_marker",
    message: `No POP root marker found in "${chosenPath}".`,
  };
}

export function writeMarker(rootPath: string, rootId: string, company = "POP Creations"): void {
  const marker: MarkerFile = {
    type: "pop-dam-root",
    root_id: rootId,
    company,
    created_by: "POP DAM Helper",
    do_not_move: true,
    schema_version: 1,
  } as MarkerFile & { created_by: string; do_not_move: boolean };
  writeFileSync(
    join(rootPath, ROOT_MARKER_FILENAME),
    JSON.stringify(marker, null, 2),
    "utf-8",
  );
}

/**
 * Preload script — exposes a safe, typed IPC bridge to the renderer.
 * The renderer never has direct access to Node or Electron APIs.
 */

import { contextBridge, ipcRenderer } from "electron";
import type { LocalConfig, IpcResponse, ValidationResult } from "../shared/types";

const api = {
  // Config
  getConfig: (): Promise<IpcResponse<LocalConfig>> =>
    ipcRenderer.invoke("get-config"),
  saveConfig: (updates: Partial<LocalConfig>): Promise<IpcResponse<LocalConfig>> =>
    ipcRenderer.invoke("save-config", updates),

  // Checkout state
  getCheckouts: (): Promise<IpcResponse<{
    checkouts: unknown[];
    uploadJobs: unknown[];
  }>> => ipcRenderer.invoke("get-checkouts"),

  // File actions
  openFile: (checkoutId: string): Promise<IpcResponse> =>
    ipcRenderer.invoke("open-file", checkoutId),
  revealFile: (checkoutId: string): Promise<IpcResponse> =>
    ipcRenderer.invoke("reveal-file", checkoutId),
  checkin: (checkoutId: string): Promise<IpcResponse> =>
    ipcRenderer.invoke("checkin", checkoutId),
  discard: (checkoutId: string): Promise<IpcResponse> =>
    ipcRenderer.invoke("discard", checkoutId),

  // Navigation
  openDam: (): Promise<IpcResponse> =>
    ipcRenderer.invoke("open-dam"),

  // Auth
  getAuthState: (): Promise<IpcResponse<{ loggedIn: boolean; userId: string | null; email: string | null; accessToken: string | null }>> =>
    ipcRenderer.invoke("get-auth-state"),
  signIn: (email: string, password: string): Promise<IpcResponse> =>
    ipcRenderer.invoke("sign-in", { email, password }),
  logout: (): Promise<IpcResponse> =>
    ipcRenderer.invoke("logout"),

  // Folder picker (native OS dialog)
  browseForFolder: (): Promise<IpcResponse<string | null>> =>
    ipcRenderer.invoke("browse-for-folder"),

  // Synology credentials
  saveSynologyCredentials: (creds: { username: string; password: string }): Promise<IpcResponse> =>
    ipcRenderer.invoke("save-synology-credentials", creds),
  hasSynologyCredentials: (): Promise<IpcResponse<boolean>> =>
    ipcRenderer.invoke("has-synology-credentials"),

  // Supabase URL auto-discovery
  discoverSupabaseUrl: (damUrl: string): Promise<IpcResponse<string>> =>
    ipcRenderer.invoke("discover-supabase-url", damUrl),

  // Server-defined root mappings
  fetchServerRoots: (): Promise<IpcResponse<Array<{ root_id: string; display_name: string; server_path: string }>>> =>
    ipcRenderer.invoke("fetch-server-roots"),

  // Root path validation (runs in main process — has filesystem access)
  validateRoot: (path: string, rootId: string): Promise<IpcResponse<ValidationResult>> =>
    ipcRenderer.invoke("validate-root", { path, rootId }),

  // Events from main → renderer
  onCheckoutsChanged: (cb: () => void): (() => void) => {
    const handler = () => cb();
    ipcRenderer.on("checkouts-changed", handler);
    return () => ipcRenderer.removeListener("checkouts-changed", handler);
  },
  onAuthChanged: (cb: () => void): (() => void) => {
    const handler = () => cb();
    ipcRenderer.on("auth-changed", handler);
    return () => ipcRenderer.removeListener("auth-changed", handler);
  },
};

contextBridge.exposeInMainWorld("popdam", api);

export type PopDamAPI = typeof api;

