  if (!token || !server) return null;

  try {
    const p = "/" + pathInLib.replace(/\\/g, "/").replace(/^\/+/, "");
    const url =
      `${server.replace(/\/$/, "")}/api2/repos/${libraryId}/file/detail/` +
      `?p=${encodeURIComponent(p)}`;
    const res = await fetch(url, {
      headers: { Authorization: `Token ${token}`, Accept: "application/json" },
    });
    if (!res.ok) {
      log.warn(`Seafile file/detail failed (${res.status}) for ${pathInLib}`);
      return null;
    }
    const json = (await res.json()) as { id?: string };
    return json.id ?? null;
  } catch (e) {
    log.warn("Seafile obj_id lookup failed:", e);
    return null;
  }
}

// ── Mapping test (Settings UI) ──────────────────────────────────────────────

export interface MappingTestResult {
  ok: boolean;
  resolvedPath?: string;
  exists?: boolean;
  message: string;
}

export function testSeafileMapping(
  rootId: string,
  sampleRelativePath: string,
  config: LocalConfig,
): MappingTestResult {
  try {
    const resolved = resolveSeafilePath(rootId, sampleRelativePath, config);
    const exists = existsSync(resolved);
    return {
      ok: true,
      resolvedPath: resolved,
      exists,
      message: exists
        ? "Mapping resolves and the path exists."
        : "Mapping resolves, but the sample path does not exist yet.",
    };
  } catch (e) {
    return { ok: false, message: e instanceof Error ? e.message : String(e) };
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

