  rootId: string;        // PopDAM root_id this library maps to
}

export interface HydrationStatus {
  state: "local" | "hydrating" | "unavailable";
  bytesDone?: number;
  bytesTotal?: number;
}

export interface CheckoutSource {
  provider: StorageProvider;
  localPath: string;
  seafileObjId?: string;
}

// ─── Checkout lifecycle ───────────────────────────────────────────────────────

export type CheckoutStatus =
  | "active"
  | "checkin_queued"
  | "uploading"
  | "verifying"
  | "complete"
  | "discarded"
  | "error"
  | "conflict";

