- name: Package with electron-builder
  env:
    GH_TOKEN: ${{ secrets.GITHUB_TOKEN }}
    # Code signing: CSC_LINK = base64 of the "Developer ID Application" .p12,
    # CSC_KEY_PASSWORD = its export password. When unset, electron-builder finds
    # no identity and produces an UNSIGNED dmg (current behaviour). When set, it
    # signs, and scripts/notarize.cjs notarizes (it needs the APPLE_* secrets too).
    CSC_LINK: ${{ secrets.CSC_LINK }}
    CSC_KEY_PASSWORD: ${{ secrets.CSC_KEY_PASSWORD }}
    APPLE_ID: ${{ secrets.APPLE_ID }}
    APPLE_APP_SPECIFIC_PASSWORD: ${{ secrets.APPLE_APP_SPECIFIC_PASSWORD }}
    APPLE_TEAM_ID: ${{ secrets.APPLE_TEAM_ID }}
  run: npx electron-builder --mac --publish never

